$(document).ready(function(){var n=$(".navbar");$(".navbar-toggler").on("click",function(e){e.preventDefault(),n.toggleClass("is-menu-opened")});var a=$(".nav-search-panel-toggle"),t=$(".nav-search-panel"),e=$(".nav-search-panel-close");a.on("click",function(e){e.preventDefault(),n.toggleClass("is-search-panel-opened")}),e.on("click",function(e){e.preventDefault(),n.removeClass("is-search-panel-opened")}),$(document).on("click touchstart",function(e){0==$(e.target).closest(t).length&&0==$(e.target).closest(a).length&&n.removeClass("is-search-panel-opened")})});